# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using System.Collections;
using System.Collections.Generic;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 500;
    
    public int baseDamage = 10;
    public int damageUpgradeLevel = 0;
    public int damageUpgradeCost = 50;
    
    public int healthUpgradeLevel = 0;
    public int healthUpgradeCost = 100;
    
    public int currencyUpgradeLevel = 0;
    public int currencyUpgradeCost = 75;
    
    public static PlayerStats instance;
    
    void Awake()
    {
        if (instance == null)
        {
            instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }
    
    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
    }
    
    public bool CanAfford(int price)
    {
        return currency >= price;
    }
    
    public void PurchaseDamageUpgrade()
    {
        if (CanAfford(damageUpgradeCost))
        {
            currency -= damageUpgradeCost;
            damageUpgradeLevel++;
            baseDamage += 5;
            damageUpgradeCost = (int)(damageUpgradeCost * 1.5f);
        }
    }
    
    public void PurchaseHealthUpgrade()
    {
        if (CanAfford(healthUpgradeCost))
        {
            currency -= healthUpgradeCost;
            healthUpgradeLevel++;
            maxHealth += 20;
            health = maxHealth;
            healthUpgradeCost = (int)(healthUpgradeCost * 1.7f);
        }
    }
    
    public void PurchaseCurrencyUpgrade()
    {
        if (CanAfford(currencyUpgradeCost))
        {
            currency -= currencyUpgradeCost;
            currencyUpgradeLevel++;
            currency += 100;
            currencyUpgradeCost = (int)(currencyUpgradeCost * 1.8f);
        }
    }
    
    public int CalculateDamage()
    {
        return baseDamage + (damageUpgradeLevel * 2);
    }
    
    public void AddCurrency(int amount)
    {
        currency += amount;
    }
    
    public void ResetStats()
    {
        health = maxHealth;
        currency = 500;
        baseDamage = 10;
        damageUpgradeLevel = 0;
        healthUpgradeLevel = 0;
        currencyUpgradeLevel = 0;
        damageUpgradeCost = 50;
        healthUpgradeCost = 100;
        currencyUpgradeCost = 75;
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats;
    
    void Start()
    {
        playerStats = PlayerStats.instance;
    }
    
    public void BuyDamageUpgrade()
    {
        playerStats.PurchaseDamageUpgrade();
    }
    
    public void BuyHealthUpgrade()
    {
        playerStats.PurchaseHealthUpgrade();
    }
    
    public void BuyCurrencyUpgrade()
    {
        playerStats.PurchaseCurrencyUpgrade();
    }
    
    public bool CanAffordDamageUpgrade()
    {
        return playerStats.CanAfford(playerStats.damageUpgradeCost);
    }
    
    public bool CanAffordHealthUpgrade()
    {
        return playerStats.CanAfford(playerStats.healthUpgradeCost);
    }
    
    public bool CanAffordCurrencyUpgrade()
    {
        return playerStats.CanAfford(playerStats.currencyUpgradeCost);
    }
}

public class Enemy : MonoBehaviour
{
    public int enemyHealth = 30;
    public int enemyDamage = 5;
    public int rewardCurrency = 25;
    
    private PlayerStats playerStats;
    
    void Start()
    {
        playerStats = PlayerStats.instance;
    }
    
    public void TakeDamage(int damage)
    {
        enemyHealth -= damage;
        if (enemyHealth <= 0)
        {
            playerStats.AddCurrency(rewardCurrency);
            Destroy(gameObject);
        }
    }
    
    void OnTriggerEnter(Collider other)
    {
        if (other.CompareTag("Player"))
        {
            playerStats.TakeDamage(enemyDamage);
            if (playerStats.health <= 0)
            {
                // Game over logic
                Debug.Log("Game Over!");
            }
        }
    }
}

public class GameManager : MonoBehaviour
{
    public PlayerStats playerStats;
    
    void Start()
    {
        playerStats = PlayerStats.instance;
    }
    
    public void OnPlayerAttack(Enemy enemy)
    {
        int damage = playerStats.CalculateDamage();
        enemy.TakeDamage(damage);
    }
    
    public void OnPlayerDeath()
    {
        // Reset game state
        playerStats.ResetStats();
    }
}